import { createHash } from "node:crypto";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const serviceRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const repositoryRoot = path.resolve(serviceRoot, "..", "..");
const manifestPath = path.join(repositoryRoot, "NULLSCAPE", "update_manifest.json");
const loaderTemplatePath = path.join(serviceRoot, "client", "secure-loader.template.luau");
const manifestSource = (await readFile(manifestPath, "utf8")).replace(/^\uFEFF/, "");
const manifest = JSON.parse(manifestSource);

if (!Array.isArray(manifest.Files) || manifest.Files.length === 0) {
  throw new Error("Update manifest contains no source files");
}

const sources = {};
for (const entry of manifest.Files) {
  const relativePath = String(entry.Path || "").replaceAll("\\", "/");
  if (!relativePath.startsWith("NULLSCAPE/") || relativePath.includes("../")) {
    throw new Error(`Unsafe manifest path: ${relativePath}`);
  }
  const absolutePath = path.resolve(repositoryRoot, ...relativePath.split("/"));
  if (!absolutePath.startsWith(path.join(repositoryRoot, "NULLSCAPE") + path.sep)) {
    throw new Error(`Manifest path escaped NULLSCAPE: ${relativePath}`);
  }
  const source = await readFile(absolutePath, "utf8");
  const actualHash = createHash("sha256").update(source).digest("hex");
  if (actualHash !== String(entry.Sha256 || "").toLowerCase()) {
    throw new Error(`Manifest hash mismatch: ${relativePath}`);
  }
  sources[relativePath] = source;
}

const payload = JSON.stringify({
  version: String(manifest.Version || "unknown"),
  master_path: "NULLSCAPE/Main UI/master.luau",
  sources,
});
const outputDirectory = path.join(serviceRoot, "generated");
await mkdir(outputDirectory, { recursive: true });
await writeFile(
  path.join(outputDirectory, "source-bundle.js"),
  `// Generated by scripts/build-source-bundle.mjs. Do not commit.\nexport const SOURCE_BUNDLE_JSON = ${JSON.stringify(payload)};\n`,
  "utf8",
);
const loaderTemplate = await readFile(loaderTemplatePath, "utf8");
if (!loaderTemplate.includes("__NULLSCAPE_AUTH_BASE_URL__")) {
  throw new Error("Secure loader template has no API base placeholder");
}
await writeFile(
  path.join(outputDirectory, "secure-loader.js"),
  `// Generated by scripts/build-source-bundle.mjs. Do not commit.\nexport const SECURE_LOADER_TEMPLATE = ${JSON.stringify(loaderTemplate)};\n`,
  "utf8",
);

console.log(`Bundled ${Object.keys(sources).length} files (${Buffer.byteLength(payload)} bytes)`);
